-- mod-battlepass v4: Custom-Items (Basisname EN, deutsche Namen via item_template_locale)
DELETE FROM `item_template` WHERE `entry` BETWEEN 900001 AND 900199;
DELETE FROM `item_template_locale` WHERE `ID` BETWEEN 900001 AND 900199;

-- ---- Klassenset Krieger ----
DROP TEMPORARY TABLE IF EXISTS `bp_tmp`;
CREATE TEMPORARY TABLE `bp_tmp` AS SELECT * FROM `item_template` WHERE `entry`=44096;
UPDATE `bp_tmp` SET `entry`=900011, `name`='Nightmare Blade', `Quality`=4, `AllowableClass`=1, `RequiredLevel`=1, `BuyPrice`=0, `SellPrice`=0, `description`='Battle Pass Saison 1 - Klassenset Krieger (Waffe), levelt bis 80 mit';
UPDATE `bp_tmp` SET `subclass` = CASE WHEN `class`=4 AND `subclass`<>6 THEN 0 WHEN `class`=2 AND `InventoryType` IN (13,17,21,22) THEN 14 ELSE `subclass` END, `RequiredSkill`=0, `RequiredSkillRank`=0;
INSERT INTO `item_template` SELECT * FROM `bp_tmp`;
